# Data types module with enums and structs

enum Status:
    ACTIVE = 0
    INACTIVE = 1
    PENDING = 2

struct Color:
    r: int
    g: int
    b: int

    def __init__(self, red: int, green: int, blue: int):
        self.r = red
        self.g = green
        self.b = blue

    def to_hex(self) -> str:
        r_hex: str = self._to_hex_digit(self.r)
        g_hex: str = self._to_hex_digit(self.g)
        b_hex: str = self._to_hex_digit(self.b)
        return "#" + r_hex + g_hex + b_hex

    def _to_hex_digit(self, value: int) -> str:
        if value < 16:
            return "0" + self._single_hex(value)
        return self._single_hex(value // 16) + self._single_hex(value % 16)

    def _single_hex(self, digit: int) -> str:
        if digit == 0:
            return "0"
        elif digit == 1:
            return "1"
        elif digit == 2:
            return "2"
        elif digit == 3:
            return "3"
        elif digit == 4:
            return "4"
        elif digit == 5:
            return "5"
        elif digit == 6:
            return "6"
        elif digit == 7:
            return "7"
        elif digit == 8:
            return "8"
        elif digit == 9:
            return "9"
        elif digit == 10:
            return "A"
        elif digit == 11:
            return "B"
        elif digit == 12:
            return "C"
        elif digit == 13:
            return "D"
        elif digit == 14:
            return "E"
        else:
            return "F"

struct Point:
    x: float
    y: float

    def __init__(self, x_val: float, y_val: float):
        self.x = x_val
        self.y = y_val

    def distance_to_origin(self) -> float:
        return (self.x * self.x + self.y * self.y) ** 0.5

def get_default_status() -> Status:
    return Status.ACTIVE

def create_red_color() -> Color:
    return Color(255, 0, 0)

def point_from_coords(coords: tuple[float, float]) -> Point:
    x_val: float = coords[0]
    y_val: float = coords[1]
    return Point(x_val, y_val)

