# Math utilities module

from types_data import Point

def square(x: float) -> float:
    return x * x

def hypotenuse(a: float, b: float) -> float:
    return (square(a) + square(b)) ** 0.5

def distance_between(p1: Point, p2: Point) -> float:
    dx: float = p1.x - p2.x
    dy: float = p1.y - p2.y
    return hypotenuse(dx, dy)

def clamp(value: float, min_val: float, max_val: float) -> float:
    if value < min_val:
        return min_val
    elif value > max_val:
        return max_val
    return value

def average(values: list[float]) -> float:
    if len(values) == 0:
        return 0.0
    total: float = 0.0
    for v in values:
        total = total + v
    return total / float(len(values))

def sum_ints(values: list[int]) -> int:
    total: int = 0
    for v in values:
        total = total + v
    return total

