# Geometry shapes module

from types_data import Point, Color, Status
from math_utils import distance_between, average

class Rectangle:
    top_left: Point
    width: float
    height: float
    fill_color: Color

    def __init__(self, tl: Point, w: float, h: float, color: Color):
        self.top_left = tl
        self.width = w
        self.height = h
        self.fill_color = color

    def area(self) -> float:
        return self.width * self.height

    def perimeter(self) -> float:
        return 2.0 * (self.width + self.height)

    def diagonal_length(self) -> float:
        return (self.width * self.width + self.height * self.height) ** 0.5

    def center(self) -> Point:
        cx: float = self.top_left.x + self.width / 2.0
        cy: float = self.top_left.y + self.height / 2.0
        return Point(cx, cy)

    def get_color_name(self) -> str:
        return self.fill_color.to_hex()

class Circle:
    center: Point
    radius: float
    border_color: Color

    def __init__(self, c: Point, r: float, color: Color):
        self.center = c
        self.radius = r
        self.border_color = color

    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    def circumference(self) -> float:
        return 2.0 * 3.14159 * self.radius

    def contains_point(self, p: Point) -> bool:
        dist: float = distance_between(self.center, p)
        return dist <= self.radius

    def get_color_name(self) -> str:
        return self.border_color.to_hex()

class ShapeCollection:
    rectangles: list[Rectangle]
    circles: list[Circle]

    def __init__(self):
        self.rectangles = []
        self.circles = []

    def add_rectangle(self, r: Rectangle) -> None:
        self.rectangles.append(r)

    def add_circle(self, c: Circle) -> None:
        self.circles.append(c)

    def total_rectangle_area(self) -> float:
        areas: list[float] = []
        for r in self.rectangles:
            areas.append(r.area())
        return average(areas) * float(len(areas))

    def total_circle_area(self) -> float:
        areas: list[float] = []
        for c in self.circles:
            areas.append(c.area())
        return average(areas) * float(len(areas))

    def get_shape_count(self) -> int:
        return len(self.rectangles) + len(self.circles)

def create_unit_square(origin: Point) -> Rectangle:
    red: Color = Color(255, 0, 0)
    return Rectangle(origin, 1.0, 1.0, red)

def create_unit_circle(center: Point) -> Circle:
    blue: Color = Color(0, 0, 255)
    return Circle(center, 1.0, blue)
